// GERA XML PARTE 01 - Preparar metadados
// Cole aqui o código do node GERA XML PARTE 01
// Disponível no arquivo: nodes/gera_xml_parte01.js

const CONSTANTS = {
  REGISTRO_ANS: '339679',
  CODIGO_PRESTADOR: '97498504',
  NOME_PRESTADOR: 'DEDICARE SERVICOS DE FONOAUDIOLOGIA PSICOLOGIA E NUTRICAO',
  CNES: '9794220',
  PADRAO_TISS: '4.02.00'
};

const parametros = $json;
const numeroLote = parametros.numeroLote;
const agora = new Date();
const dataTransacao = agora.toISOString().split('T')[0];
const horaTransacao = agora.toTimeString().split(' ')[0];

return [{
  json: {
    numeroLote,
    dataTransacao,
    horaTransacao,
    ...CONSTANTS,
    guias: [] // Será preenchido após ler Google Sheets
  }
}];

// MONTAR XML FINAL - Juntar todas as guias
// Cole aqui o código do node MONTAR XML FINAL
// Disponível no arquivo: nodes/montar_xml_final.js

const items = $input.all();
const primeiro = items[0].json;

let guiasXml = '';
for (const item of items) {
  guiasXml += item.json.xmlProcedimento;
}

const xmlFinal = `<?xml version="1.0" encoding="ISO-8859-1" standalone="yes"?>
<ans:mensagemTISS xmlns:ans="http://www.ans.gov.br/padroes/tiss/schemas" xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
  <ans:cabecalho>
    <ans:identificacaoTransacao>
      <ans:tipoTransacao>ENVIO_LOTE_GUIAS</ans:tipoTransacao>
      <ans:sequencialTransacao>${primeiro.numeroLote}</ans:sequencialTransacao>
      <ans:dataRegistroTransacao>${primeiro.dataTransacao}</ans:dataRegistroTransacao>
      <ans:horaRegistroTransacao>${primeiro.horaTransacao}</ans:horaRegistroTransacao>
    </ans:identificacaoTransacao>
    <ans:origem>
      <ans:identificacaoPrestador>
        <ans:codigoPrestadorNaOperadora>${String(primeiro.codigoPrestador).padStart(20, '0')}</ans:codigoPrestadorNaOperadora>
      </ans:identificacaoPrestador>
    </ans:origem>
    <ans:destino>
      <ans:registroANS>${primeiro.registroANS}</ans:registroANS>
    </ans:destino>
    <ans:Padrao>4.02.00</ans:Padrao>
  </ans:cabecalho>
  <ans:prestadorParaOperadora>
    <ans:loteGuias>
      <ans:numeroLote>${primeiro.numeroLote}</ans:numeroLote>
      <ans:guiasTISS>
${guiasXml}
      </ans:guiasTISS>
    </ans:loteGuias>
  </ans:prestadorParaOperadora>
</ans:mensagemTISS>`;

return [{ json: { xml: xmlFinal, numeroLote: primeiro.numeroLote, qtdGuias: items.length } }];
